import React, { useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faChevronLeft, faChevronRight, faChevronDown, faEye, faCartPlus, faSearch } from '@fortawesome/free-solid-svg-icons';
import { products } from '../data/products';
import { useWishlist } from '../context/WishlistContext';
import './ShopPage.css';

const categories = [
  { key: 'all', label: 'All' },
  { key: 'soaps', label: 'Soaps' },
  { key: 'shampoos', label: 'Shampoos' },
  { key: 'face-wash', label: 'Face Wash' },
  { key: 'face-packs', label: 'Face Packs' },
  { key: 'oils', label: 'Oils' },
  { key: 'balms', label: 'Balms' },
];

export default function ShopPage() {
  const [activeCategory, setActiveCategory] = useState('all');
  const [sortBy, setSortBy] = useState('bestselling');
  const [searchQuery, setSearchQuery] = useState('');
  const { addToWishlist } = useWishlist();
  const [added, setAdded] = useState({});

  const filtered = useMemo(() => {
    let list = activeCategory === 'all' ? [...products] : products.filter(p => p.category === activeCategory);

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      list = list.filter(p => p.name.toLowerCase().includes(q) || p.subtitle.toLowerCase().includes(q));
    }

    if (sortBy === 'price-low') list.sort((a, b) => a.price - b.price);
    else if (sortBy === 'price-high') list.sort((a, b) => b.price - a.price);
    else if (sortBy === 'newest') list.sort((a, b) => b.id - a.id);
    else if (sortBy === 'bestselling') list.sort((a, b) => b.reviews - a.reviews);

    return list;
  }, [activeCategory, sortBy, searchQuery]);

  const handleAdd = (e, product) => {
    e.preventDefault();
    e.stopPropagation();
    addToWishlist(product);
    setAdded(prev => ({ ...prev, [product.id]: true }));
    setTimeout(() => setAdded(prev => ({ ...prev, [product.id]: false })), 1500);
  };

  return (
    <div className="shop">
      {/* Header */}
      <header className="shop__header">
        <h1 className="font-display-lg shop__title">Herbal Products</h1>
        <p className="font-body-lg shop__sub">
          Purely natural, carefully crafted rituals for the modern skin. Made in small batches for the best quality.
        </p>
      </header>

      {/* Filters */}
      <section className="shop__section container-max">
        <div className="shop__search-bar">
          <FontAwesomeIcon icon={faSearch} className="shop__search-icon" />
          <input 
            type="text" 
            placeholder="Search herbal products..." 
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            className="shop__search-input font-body-sm"
          />
        </div>
        <div className="shop__filters-row">
          <div className="shop__filters">
            {categories.map(cat => (
              <button
                key={cat.key}
                className={`shop__filter-btn font-label-sm ${activeCategory === cat.key ? 'shop__filter-btn--active' : ''}`}
                onClick={() => setActiveCategory(cat.key)}
              >
                {cat.label}
              </button>
            ))}
          </div>
          <div className="shop__sort-wrap">
            <select
              className="shop__sort font-label-sm"
              value={sortBy}
              onChange={e => setSortBy(e.target.value)}
            >
              <option value="bestselling">Sort by: Bestselling</option>
              <option value="price-low">Price: Low to High</option>
              <option value="price-high">Price: High to Low</option>
              <option value="newest">Newest Arrivals</option>
            </select>
            <FontAwesomeIcon icon={faChevronDown} className="shop__sort-icon" />
          </div>
        </div>

        {/* Product Grid */}
        <div className="shop__grid">
          {filtered.map(product => (
            <Link to={`/product/${product.id}`} key={product.id} className="shop__card">
              <div className="shop__card-img-wrap">
                <img src={product.image} alt={product.name} className="shop__card-img" />
                <div className="shop__card-actions">
                  <button
                    className="shop__card-add font-label-md"
                    onClick={e => handleAdd(e, product)}
                  >
                    {added[product.id] ? (
                      <><FontAwesomeIcon icon={faCartPlus} /> Added!</>
                    ) : (
                      'Add to Order'
                    )}
                  </button>
                  <button
                    className="shop__card-view"
                    onClick={e => e.stopPropagation()}
                    tabIndex={-1}
                  >
                    <FontAwesomeIcon icon={faEye} />
                  </button>
                </div>
              </div>
              <div className="shop__card-body">
                {product.tags && product.tags.length > 0 && (
                  <div className="shop__card-tags">
                    {product.tags.map(tag => (
                      <span key={tag} className="shop__tag font-label-sm">{tag}</span>
                    ))}
                  </div>
                )}
                <h3 className="font-headline-sm shop__card-name">{product.name}</h3>
                <p className="font-body-sm shop__card-sub">{product.subtitle} | {product.size}</p>
                <p className="font-headline-sm shop__card-price">₹{product.price.toLocaleString()}</p>
              </div>
            </Link>
          ))}
        </div>

        {/* Pagination */}
        <div className="shop__pagination">
          <button className="shop__page-btn">
            <FontAwesomeIcon icon={faChevronLeft} />
          </button>
          <span className="shop__page-num shop__page-num--active font-label-md">1</span>
          <button className="shop__page-num font-label-md">2</button>
          <button className="shop__page-num font-label-md">3</button>
          <button className="shop__page-btn">
            <FontAwesomeIcon icon={faChevronRight} />
          </button>
        </div>
      </section>
    </div>
  );
}
